import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { LiveSessionsService } from '../../services';
import { LiveSession } from '../../models';

@Component({
  selector: 'app-live-sessions',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './live-sessions.component.html',
  styleUrls: ['./live-sessions.component.scss']
})
export class LiveSessionsComponent implements OnInit {
  sessions: LiveSession[] = [];
  loading = true;

  constructor(private liveSessionsService: LiveSessionsService) {}

  ngOnInit() {
    this.loadSessions();
  }

  loadSessions() {
    this.liveSessionsService.getLiveSessions().subscribe(sessions => {
      this.sessions = sessions;
      this.loading = false;
    });
  }

  joinSession(sessionId: string) {
    this.liveSessionsService.joinSession(sessionId).subscribe(response => {
      // Open Jitsi Meet in modal or new window
      const url = `https://meet.jit.si/${response.roomName}`;
      window.open(url, '_blank');
    });
  }

  getStatusClass(status: string): string {
    switch (status) {
      case 'live': return 'bg-red-100 text-red-600';
      case 'scheduled': return 'bg-blue-100 text-blue-600';
      case 'ended': return 'bg-gray-100 text-gray-600';
      default: return 'bg-gray-100 text-gray-600';
    }
  }
}
<div class="min-h-screen bg-gray-50 py-8">
  <div class="max-w-7xl mx-auto px-4">
    <!-- Header -->
    <div class="text-center mb-8">
      <h1 class="text-4xl font-bold text-gray-900 mb-4">Live Sessions</h1>
      <p class="text-xl text-gray-600">Join interactive live classes with expert teachers</p>
    </div>

    <!-- Loading State -->
    <div *ngIf="loading" class="grid md:grid-cols-3 gap-6">
      <div *ngFor="let item of [1,2,3,4,5,6]" class="bg-white rounded-lg shadow-md p-6">
        <div class="loading-skeleton h-6 mb-4"></div>
        <div class="loading-skeleton h-4 mb-2"></div>
        <div class="loading-skeleton h-4 mb-4"></div>
        <div class="loading-skeleton h-10"></div>
      </div>
    </div>

    <!-- Sessions Grid -->
    <div *ngIf="!loading" class="grid md:grid-cols-3 gap-6">
      <div *ngFor="let session of sessions" class="bg-white rounded-lg shadow-lg overflow-hidden card-hover">
        <div class="p-6">
          <div class="flex items-center justify-between mb-4">
            <span [class]="'px-3 py-1 rounded-full text-sm font-medium ' + getStatusClass(session.status)">
              {{ session.status }}
            </span>
            <span class="text-sm text-gray-500">
              {{ session.duration }}min
            </span>
          </div>

          <h3 class="text-xl font-semibold text-gray-900 mb-2">{{ session.title }}</h3>
          <p class="text-gray-600 mb-4">{{ session.teacherName }}</p>

          <div *ngIf="session.courseName" class="text-sm text-gray-500 mb-4">
            <strong>Course:</strong> {{ session.courseName }}
          </div>

          <div class="text-sm text-gray-500 mb-4">
            <strong>Scheduled:</strong> {{ session.scheduledAt | date:'longDate' }} at {{ session.scheduledAt | date:'shortTime' }}
          </div>

          <div *ngIf="session.participantCount" class="text-sm text-gray-500 mb-4">
            <strong>Participants:</strong> {{ session.participantCount }}
          </div>

          <button (click)="joinSession(session.id)" 
                  [disabled]="session.status !== 'live'"
                  class="w-full btn-gradient disabled:opacity-50 disabled:cursor-not-allowed">
            {{ session.status === 'live' ? 'Join Session' : 'Not Available' }}
          </button>
        </div>
      </div>
    </div>

    <!-- Empty State -->
    <div *ngIf="!loading && sessions.length === 0" class="text-center py-12">
      <div class="text-gray-400 mb-4">
        <svg class="w-24 h-24 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 10l4.553-2.276A1 1 0 0016 7v4a1 1 0 00-.447.894L11 14m0 0V8a2 2 0 10-4 0v6a2 2 0 104 0m0 0V8a2 2 0 10-4 0v6a2 2 0 104 0z"/>
        </svg>
      </div>
      <h3 class="text-xl font-semibold text-gray-900 mb-2">No live sessions</h3>
      <p class="text-gray-600">Check back later for upcoming sessions</p>
    </div>
  </div>
</div>
